body.script:
        // Định nghĩa hệ tọa độ EPSG:3857 cho bộ chuyển đổi
        var crs3857 = new L.Proj.CRS('EPSG:3857',
            '+proj=merc +a=6378137 +b=6378137 +lat_ts=0 +lon_0=0 +x_0=0 +y_0=0 +k=1 +units=m +nadgrids=@null +wktext +no_defs',
            {
                resolutions: [
                    156543.03392804097, 78271.51696402048, 39135.75848201024,
                    19567.87924100512, 9783.93962050256, 4891.96981025128,
                    2445.98490512564, 1222.99245256282, 611.49622628141,
                    305.748113140705, 152.8740565703525, 76.43702828517625,
                    38.21851414258813, 19.109257071294063, 9.554628535647032,
                    4.777314267823516, 2.388657133911758, 1.194328566955879,
                    0.5971642834779395, 0.29858214173896974
                ]
            }
        );

        // Khởi tạo bản đồ nền (Sử dụng hệ tọa độ chuẩn của Web)
        var map = L.map('map').setView([16.047079, 108.206230], 6);

        // Thêm lớp bản đồ nền OpenStreetMap
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: '© OpenStreetMap contributors'
        }).addTo(map);

        // Hàm chuyển đổi hình học từ dữ liệu EPSG:3857 sang tọa độ Leaflet hiển thị được
        function convertCoords(coords, type) {
            if (type === 'Point') {
                var pt = proj4('EPSG:3857', 'EPSG:4326', coords);
                return [pt[1], pt[0]];
            } else if (type === 'LineString' || type === 'MultiPoint') {
                return coords.map(c => { var pt = proj4('EPSG:3857', 'EPSG:4326', c); return [pt[1], pt[0]]; });
            } else if (type === 'Polygon' || type === 'MultiLineString') {
                return coords.map(ring => ring.map(c => { var pt = proj4('EPSG:3857', 'EPSG:4326', c); return [pt[1], pt[0]]; }));
            } else if (type === 'MultiPolygon') {
                return coords.map(poly => poly.map(ring => ring.map(c => { var pt = proj4('EPSG:3857', 'EPSG:4326', c); return [pt[1], pt[0]]; })));
            }
            return coords;
        }

        // Tải và xử lý file dữ liệu GeoJSON
        fetch('map_data.geojson')
            .then(response => response.json())
            .then(data => {
                
                // Tiền xử lý tọa độ trong file GeoJSON từ 3857 sang định dạng Leaflet hiểu được
                var convertedData = JSON.parse(JSON.stringify(data)); 
                convertedData.features.forEach(feature => {
                    if (feature.geometry) {
                        feature.geometry.coordinates = convertCoords(feature.geometry.coordinates, feature.geometry.type);
                    }
                });

                // Hiển thị lớp dữ liệu lên bản đồ
                var geojsonLayer = L.geoJSON(convertedData, {
                    style: function (feature) {
                        return {
                            color: "#3388ff", // Màu đường viền đối tượng
                            weight: 2,
                            opacity: 0.8,
                            fillColor: "#3388ff", // Màu nền đối tượng (Polygon)
                            fillOpacity: 0.4
                        };
                    },
                    onEachFeature: function (feature, layer) {
                        // Hiển thị thông tin thuộc tính dạng bảng danh sách khi click
                        layer.on('click', function (e) {
                            var properties = feature.properties;
                            var htmlContent = "";
                            for (var key in properties) {
                                htmlContent += `
${key}: ${properties[key]}`;
                            }
                            htmlContent += "";
                            document.getElementById('feature-info').innerHTML = htmlContent;
                            
                            // Highlight nhẹ đối tượng khi được click
                            if (typeof layer.setStyle === 'function') {
                                geojsonLayer.resetStyle();
                                layer.setStyle({ weight: 4, color: '#ff3333', fillOpacity: 0.6 });
                            }
                        });
                    }
                }).addTo(map);

                // Tự động căn chỉnh màn hình vừa vặn với toàn bộ khu vực của dữ liệu
                map.fitBounds(geojsonLayer.getBounds());
            })
            .catch(error => {
                console.error('Lỗi khi đọc file GeoJSON:', error);
                document.getElementById('feature-info').innerHTML = "
Không thể tải dữ liệu bản đồ. Hãy chắc chắn file map_data.geojson nằm cùng thư mục với file index.html";
            });
